parameters.jsCode:
// Get the HTML content from the Formatter agent output
const item = $input.first().json;
let html = item.output || item.text || item.response || item.message || "";

if (typeof html !== 'string') {
  html = html.content || html.html || JSON.stringify(html);
}

// 1. Remove newlines and carriage returns 
// NOTE: If you want to keep the report's formatting, change this to .replace(/[\n\r]+/g, ' ')
html = html.replace(/[\n\r]/g, ' ');

// 2. Remove tabs and sequences of multiple spaces
html = html.replace(/\t/g, '');
html = html.replace(/\s{2,}/g, ' ');

// 3. Remove meaningless empty tags
html = html.replace(/<(span|p|div|section)>\s*<\/\1>/gi, '');

// 4. Strip stray markdown code fences
html = html.replace(/^```html|```$/g, '');

// 5. Trim
html = html.trim();

/**
 * 6. SQL SAFETY & CHARACTER CLEANUP
 * This is the most important part for your specific error.
 */

// Escape single quotes by doubling them (Standard SQL Requirement)
// This turns L'INSTITUT into L''INSTITUT so the DB doesn't crash
html = html.replace(/'/g, "''");

// Remove or replace Null characters which can terminate strings prematurely in some DBs
html = html.replace(/\0/g, '');

// Optional: Replace "Smart Quotes" (curly quotes from Word/Mac) with standard quotes 
// before they get escaped, as they sometimes cause encoding issues.
html = html.replace(/[\u2018\u2019]/g, "''") // Smart single quotes
           .replace(/[\u201C\u201D]/g, '"'); // Smart double quotes

return [{
  json: {
    ...item,
    cleaned_html: html
  }
}];

